function sliderPhoto() {
    var swiper = new Swiper('.photo .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 24,
        speed: 500,
        breakpoints: {
            320: {
                slidesPerView: 1.2,
                spaceBetween: 12,
            },
            768: {
                slidesPerView: 2.35,
                spaceBetween: 12,
            },
            993: {
                slidesPerView: 2.35,
                spaceBetween: 24,
            },
            1601: {
                slidesPerView: 2,
                spaceBetween: 24,
            }
        }
    })
}

function sliderProjects() {
    var swiper = new Swiper('.projects .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 24,
        speed: 500,
        navigation: {
            nextEl: ".projects .swiper-button-next",
            prevEl: ".projects .swiper-button-prev",
        },
        breakpoints: {
            320: {
                slidesPerView: 1,
                spaceBetween: 12,
            },
            577: {
                slidesPerView: 1.5,
                spaceBetween: 12,
            },
            768: {
                slidesPerView: 2,
                spaceBetween: 12,
            },
            993: {
                slidesPerView: 2,
                spaceBetween: 24,
            }
        }
    })
}

$(document).ready(function () {
  sliderPhoto();
  sliderProjects();

    // Tabs
    $(".tab").click(function () {
        let path = $(this).attr("data-tab-path")
        $(this).siblings(".tab").removeClass("tab--active")
        $(this).addClass("tab--active")

        $(this).parents(".tabs-inner").find(".tab__content").removeClass("tab__content--active")
        $(this).parents(".tabs-inner").find(`.tab__content[data-content-path="${path}"]`).addClass("tab__content--active")
    })

    // Tabs--modal
    $(".tab-modal").click(function () {
        let path = $(this).attr("data-tab-path")
        $(this).siblings(".tab-modal").removeClass("tab-modal--active")
        $(this).addClass("tab-modal--active")

        $(this).parents(".wrapper").find(".tab-modal__content").removeClass("tab-modal__content--active")
        $(this).parents(".wrapper").find(`.tab-modal__content[data-content-path="${path}"]`).addClass("tab-modal__content--active")
    })

    // Modal
    $("[data-modal]").click(function () {
        let modalId = $(this).attr("data-modal")

        openModal(modalId)
    })

    function openModal(modalId){
        $(`#${modalId}`).addClass("modal--active")
        $("body").addClass("fixed-body")
    }

    $(".modal").click(function () {
        closeModal()
    })

    $("._close-modal").click(function () {
        closeModal()
    })

    $(".modal__dialog").click(function (e) {
        e.stopPropagation()
    })

    function closeModal() {
        $('.modal--active video').each(function () {
            this.pause();
            this.currentTime = 0;
        });

        $('.modal').removeClass("modal--active")
        $("body").removeClass("fixed-body")
    }


})

 // Zoom
    if (window.innerWidth <= 992) {

  const zoomBlocks = document.querySelectorAll('.js-pinch-zoom');

  zoomBlocks.forEach((box) => {

    const img = box.querySelector('img');
    const svg = box.querySelector('svg');

    /*
    =========================
    IMG
    =========================
    */

    if (img) {

      let scale = 1;

      let startDist = 0;

      let pointX = 0;
      let pointY = 0;

      let startX = 0;
      let startY = 0;

      let isDragging = false;

      function updateTransform() {

        img.style.transform =
          `translate(${pointX}px, ${pointY}px) scale(${scale})`;
      }

      function getDistance(touches) {

        const dx =
          touches[0].clientX - touches[1].clientX;

        const dy =
          touches[0].clientY - touches[1].clientY;

        return Math.sqrt(dx * dx + dy * dy);
      }

      // START
      box.addEventListener('touchstart', (e) => {

        // zoom
        if (e.touches.length === 2) {

          startDist = getDistance(e.touches);
        }

        // drag
        if (
          e.touches.length === 1 &&
          scale > 1
        ) {

          isDragging = true;

          startX =
            e.touches[0].clientX - pointX;

          startY =
            e.touches[0].clientY - pointY;
        }

      }, { passive: false });

      // MOVE
      box.addEventListener('touchmove', (e) => {

        // zoom
        if (e.touches.length === 2) {

          e.preventDefault();

          const newDist =
            getDistance(e.touches);

          const delta =
            newDist / startDist;

          scale = Math.min(
            Math.max(scale * delta, 1),
            4
          );

          updateTransform();

          startDist = newDist;
        }

        // drag
        if (
          e.touches.length === 1 &&
          isDragging &&
          scale > 1
        ) {

          e.preventDefault();

          pointX =
            e.touches[0].clientX - startX;

          pointY =
            e.touches[0].clientY - startY;

          updateTransform();
        }

      }, { passive: false });

      // END
      box.addEventListener('touchend', () => {

        isDragging = false;

        if (scale <= 1) {

          scale = 1;

          pointX = 0;
          pointY = 0;

          updateTransform();
        }

      });
    }

    /*
    =========================
    SVG
    =========================
    */

    if (svg) {

      const baseViewBox =
        svg.viewBox.baseVal;

      let viewBox = {
        x: baseViewBox.x,
        y: baseViewBox.y,
        width: baseViewBox.width,
        height: baseViewBox.height
      };

      let startDist = 0;

      let startX = 0;
      let startY = 0;

      let isDragging = false;

      function updateViewBox() {

        svg.setAttribute(
          'viewBox',
          `${viewBox.x}
           ${viewBox.y}
           ${viewBox.width}
           ${viewBox.height}`
        );
      }

      function getDistance(touches) {

        const dx =
          touches[0].clientX - touches[1].clientX;

        const dy =
          touches[0].clientY - touches[1].clientY;

        return Math.sqrt(dx * dx + dy * dy);
      }

      // START
      box.addEventListener('touchstart', (e) => {

        // zoom
        if (e.touches.length === 2) {

          startDist = getDistance(e.touches);
        }

        // drag
        if (e.touches.length === 1) {

          isDragging = true;

          startX = e.touches[0].clientX;
          startY = e.touches[0].clientY;
        }

      }, { passive: false });

      // MOVE
      box.addEventListener('touchmove', (e) => {

        // zoom
        if (e.touches.length === 2) {

          e.preventDefault();

          const newDist =
            getDistance(e.touches);

          const delta =
            startDist / newDist;

          viewBox.width *= delta;
          viewBox.height *= delta;

          updateViewBox();

          startDist = newDist;
        }

        // drag
        if (
          e.touches.length === 1 &&
          isDragging
        ) {

          e.preventDefault();

          const dx =
            e.touches[0].clientX - startX;

          const dy =
            e.touches[0].clientY - startY;

          const moveX =
            dx *
            (viewBox.width / box.clientWidth);

          const moveY =
            dy *
            (viewBox.height / box.clientHeight);

          viewBox.x -= moveX;
          viewBox.y -= moveY;

          updateViewBox();

          startX = e.touches[0].clientX;
          startY = e.touches[0].clientY;
        }

      }, { passive: false });

      // END
      box.addEventListener('touchend', () => {

        isDragging = false;
      });
    }

  });

}
